/**
 * Over the top cute cookie consent banner. Looks good, but tries to be cute and
 * friendly more so than tie in with the websites existing design.
 *
 * @param {Props} props
 */
export default function CookieConsentB({ onAnswer, onDone }) {
  /**
   * @param {import('../CookieConsentWrapper').CookieConsentAnswer} answer
   */
  function onAnswerWrapper(answer) {
    onAnswer(answer);
    onDone();
  }

  return (
    <>
      <SpriteSheet />
      <div className={styles.wrapper}>
        <div className={styles.mascot}>
          <TrixieFace />
        </div>
        <div className={styles.bannerContainer}>
          <div className={styles.speechBubble}>
            <SpeechBubble />
          </div>
          <div className={clsx(styles.speechBubble, styles.speechBubbleWide)}>
            <SpeechBubbleWide />
          </div>
          <div className={styles.title}>
            <svg viewBox="0 0 92 30" role="heading" aria-level={2}>
              <defs>
                <path id="curve" d="M9 29q30-28 76 -13"></path>
                <path id="curveWide" d="M6 15q30-11 80 2"></path>
              </defs>
              <text fontSize="8.2">
                <textPath
                  href="#curve"
                  className={styles.curve}
                  fill="currentColor"
                >
                  Want some cookies?
                </textPath>
                <textPath
                  href="#curveWide"
                  className={styles.curveWide}
                  fill="currentColor"
                >
                  Want some cookies?
                </textPath>
              </text>
            </svg>
          </div>
          <p className={styles.copy}>
            <span className={styles.float}></span>
            We&apos;d like to use one small cookie to see how people use this site.
            Just anonymous stats, nothing more! Plausible Analytics keeps
            running either way, no cookie needed. Curious? Learn more in our <Link href="/privacy/">Privacy&nbsp;Policy</Link>.
          </p>
          <div className={styles.buttonContainer}>
            <button
              className={clsx(styles.button, styles.acceptButton)}
              onClick={() => onAnswerWrapper('accepted')}
            >
              <div className={styles.bubble}>
                <AcceptBubble />
              </div>
              <div className={clsx(styles.bubble, styles.hover)}>
                <AcceptBubbleHover />
              </div>
              <div className={styles.label}>Accept</div>
            </button>
            <button
              className={styles.button}
              onClick={() => onAnswerWrapper('rejected')}
            >
              <div className={styles.bubble}>
                <RejectBubble />
              </div>
              <div className={clsx(styles.bubble, styles.hover)}>
                <RejectBubbleHover />
              </div>
              <div className={styles.label}>Decline</div>
            </button>
          </div>
        </div>
      </div>
    </>
  );
}
